        if (--freq[nums[l]] == 0) freq.erase(nums[l]);
        l++;
    }
    best = max(best, r - l + 1);                 // 3. Update optimum
}

// --- Fixed-size window (evict left when window exceeds k) ---
for (int r = 0; r < n; r++) {
    freq[nums[r]]++;
    if (r >= k) { if (--freq[nums[r-k]] == 0) freq.erase(nums[r-k]); } // Evict
    if (r >= k-1) best = max(best, (int)freq.size()); // or whatever metric
}

