// --- Approach 1: STL nth_element (Highly recommended) ---
// Find the Kth LARGEST element (k is 1-indexed)
int k = 2;
std::nth_element(nums.begin(), nums.begin() + k - 1, nums.end(), greater<int>());
return nums[k - 1];

// --- Approach 2: Iterative Quick Select (3-Way Dutch National Flag) ---
int left = 0, right = nums.size() - 1, targetIdx = k - 1;
while (left <= right) {
    if (left == right) return nums[left];
    int pivotVal = nums[left + rand() % (right - left + 1)]; // Random pivot!
    int hi = left, lo = right;
    for (int i = left; i <= lo;) {
        if      (nums[i] > pivotVal) swap(nums[hi++], nums[i++]); // > pv: front
        else if (nums[i] < pivotVal) swap(nums[i], nums[lo--]);   // < pv: back
        else                         i++;                          // == pv: skip
    }
    // [left, hi-1] > pv | [hi, lo] == pv | [lo+1, right] < pv (for Kth largest)
    if      (targetIdx < hi) right = hi - 1;
    else if (targetIdx > lo) left  = lo + 1;
    else                     return pivotVal;
}

