stack<int> stk; // Stores sign & result when entering '('
int result = 0, num = 0, sign = 1;
for (char c : s) {
    if (isdigit(c)) {
        num = num * 10 + (c - '0'); // Multi-digit number accumulation
    } else if (c == '+' || c == '-') {
        result += sign * num; num = 0;
        sign = (c == '+') ? 1 : -1;
    } else if (c == '(') {
        stk.push(result); stk.push(sign); // Save state
        result = 0; sign = 1;
    } else if (c == ')') {
        result += sign * num; num = 0;
        result *= stk.top(); stk.pop();   // Restore sign before '('
        result += stk.top(); stk.pop();   // Restore result before '('
    }
}
return result + sign * num;

