// --- DFS: Bottom-Up (compute and return state from children) ---
int dfs(TreeNode* root) {
    if (!root) return 0; // Base case
    int left  = dfs(root->left);
    int right = dfs(root->right);
    // Process: use left and right subtree results
    diameter = max(diameter, left + right); // e.g., for tree diameter
    return max(left, right) + 1;
}

// --- LCA (Lowest Common Ancestor) ---
TreeNode* lca(TreeNode* root, TreeNode* p, TreeNode* q) {
    if (!root || root == p || root == q) return root;
    TreeNode* left  = lca(root->left, p, q);
    TreeNode* right = lca(root->right, p, q);
    if (left && right) return root; // p and q in different subtrees
    return left ? left : right;
}

// --- BFS: Level Order ---
queue<TreeNode*> q;
if (root) q.push(root);
while (!q.empty()) {
    int size = q.size(); // Snapshot size BEFORE processing this level
    for (int i = 0; i < size; i++) {
        TreeNode* node = q.front(); q.pop();
        if (node->left)  q.push(node->left);
        if (node->right) q.push(node->right);
    }
}

Trie (Prefix Tree).code:
struct TrieNode {
    TrieNode* next[26] = {NULL};
    bool isEnd = false;
    ~TrieNode() { // Destructor prevents memory leaks
        for (TrieNode* node : next)
            if (node != NULL) delete node;
    }
};

void insert(TrieNode* root, const string& word) {
    TrieNode* node = root;
    for (char c : word) {
        if (node->next[c - 'a'] == NULL)
            node->next[c - 'a'] = new TrieNode();
        node = node->next[c - 'a'];
    }
    node->isEnd = true;
}

// Exact word match: path must exist AND isEnd must be true
bool search(TrieNode* root, const string& word) {
    TrieNode* node = root;
    for (char c : word) {
        if (node->next[c - 'a'] == NULL) return false;
        node = node->next[c - 'a'];
    }
    return node->isEnd; // Key difference from startsWith
}

// Prefix match: path must exist, isEnd NOT required
bool startsWith(TrieNode* root, const string& prefix) {
    TrieNode* node = root;
    for (char c : prefix) {
        if (node->next[c - 'a'] == NULL) return false;
        node = node->next[c - 'a'];
    }
    return true;
}

