// --- Serialize: Preorder with '#' as null markers ---
string serialize(TreeNode* root) {
    if (!root) return "#,";
    return to_string(root->val) + "," + serialize(root->left) + serialize(root->right);
}

// --- Deserialize: Preorder reconstruction ---
TreeNode* deserializeHelper(istringstream& ss) {
    string val;
    getline(ss, val, ',');
    if (val == "#") return nullptr;
    TreeNode* node = new TreeNode(stoi(val));
    node->left  = deserializeHelper(ss);
    node->right = deserializeHelper(ss);
    return node;
}
TreeNode* deserialize(string data) {
    istringstream ss(data);
    return deserializeHelper(ss);
}

// --- Construct from Preorder + Inorder (use a hashmap for O(N)) ---
unordered_map<int, int> inorderIdx;
TreeNode* build(vector<int>& pre, int preL,
                vector<int>& in,  int inL, int inR) {
    if (inL > inR) return nullptr;
    TreeNode* root = new TreeNode(pre[preL]);
    int mid = inorderIdx[pre[preL]]; // O(1) lookup
    int leftSize = mid - inL;
    root->left  = build(pre, preL + 1,            in, inL,       mid - 1);
    root->right = build(pre, preL + 1 + leftSize, in, mid + 1,   inR);
    return root;
}

Backtracking (Perm / Comb / Subset).code:
// --- Combination (sorted input, skip duplicates, no reuse) ---
void backtrack_comb(vector<int>& cands, vector<int>& cur, int target, int start) {
    if (target == 0) { result.push_back(cur); return; }
    for (int i = start; i < (int)cands.size(); i++) {
        if (cands[i] > target) break;                                        // prune: sorted
        if (i > start && cands[i] == cands[i-1]) continue;                  // skip dup
        cur.push_back(cands[i]);
        backtrack_comb(cands, cur, target - cands[i], i + 1); // i+1 = no reuse
        cur.pop_back();
    }
}

// --- Permutation (sort first; visited[] tracks current path) ---
void backtrack_perm(vector<int>& nums, vector<int>& cur, vector<bool>& vis) {
    if ((int)cur.size() == (int)nums.size()) { result.push_back(cur); return; }
    for (int i = 0; i < (int)nums.size(); i++) {
        if (vis[i]) continue;
        if (i > 0 && nums[i] == nums[i-1] && !vis[i-1]) continue;           // skip dup
        vis[i] = true; cur.push_back(nums[i]);
        backtrack_perm(nums, cur, vis);
        cur.pop_back(); vis[i] = false;
    }
}

