// --- DFS 3-Color Cycle Detection (Directed Graph) ---
// WHITE=0 (unvisited), GRAY=1 (in current DFS stack), BLACK=2 (fully done)
vector<int> color(n, 0);
bool hasCycle = false;

function<void(int)> dfs = [&](int u) {
    color[u] = 1; // Mark GRAY
    for (int v : graph[u]) {
        if (color[v] == 1) { hasCycle = true; return; } // Back edge = cycle!
        if (color[v] == 0) dfs(v);
    }
    color[u] = 2; // Mark BLACK (fully processed)
};

for (int i = 0; i < n; i++)
    if (color[i] == 0) dfs(i);

// --- DFS Cycle Detection (Undirected Graph) ---
// Track parent to avoid treating the edge we came from as a back edge
function<bool(int, int)> dfsCycle = [&](int u, int parent) -> bool {
    color[u] = 1;
    for (int v : graph[u]) {
        if (v == parent) continue;  // Ignore the edge we came from
        if (color[v] == 1) return true; // Back edge = cycle
        if (color[v] == 0 && dfsCycle(v, u)) return true;
    }
    color[u] = 2;
    return false;
};

