Union-Find (DSU).code:
struct DSU {
    vector<int> parent, sz;
    DSU(int n) {
        parent.resize(n);
        sz.assign(n, 1);
        iota(parent.begin(), parent.end(), 0); // parent[i] = i
    }

    int find(int i) { // Iterative Path Halving (optimal speed & space)
        while (i != parent[i]) {
            parent[i] = parent[parent[i]]; // Path halving
            i = parent[i];
        }
        return i;
    }

    bool unite(int i, int j) { // Returns true if a merge actually happened
        int ri = find(i), rj = find(j);
        if (ri == rj) return false; // Already in same component
        if (sz[ri] < sz[rj]) swap(ri, rj); // Union by Size
        parent[rj] = ri;
        sz[ri] += sz[rj];
        return true;
    }

    bool connected(int i, int j) { return find(i) == find(j); }
};

