Knapsack DP (0/1 vs Unbounded).code:
// --- 0/1 Knapsack (each item used AT MOST ONCE) ---
// Iterate weight BACKWARDS to prevent reusing the same item
vector<int> dp(W + 1, 0);
for (auto& [weight, value] : items)
    for (int w = W; w >= weight; w--)       // <-- BACKWARDS
        dp[w] = max(dp[w], dp[w - weight] + value);

// --- Unbounded Knapsack (each item can be reused UNLIMITED times) ---
// Iterate weight FORWARDS to allow reusing the same item
vector<int> dp(W + 1, 0);
for (auto& [weight, value] : items)
    for (int w = weight; w <= W; w++)       // <-- FORWARDS
        dp[w] = max(dp[w], dp[w - weight] + value);

// --- Partition Equal Subset Sum (0/1 Knapsack on bool dp) ---
int total = reduce(nums.begin(), nums.end(), 0);
if (total % 2 != 0) return false; // Odd sum: impossible
int target = total / 2;
vector<bool> dp(target + 1, false);
dp[0] = true;
for (int num : nums)
    for (int w = target; w >= num; w--)     // <-- BACKWARDS (0/1)
        dp[w] = dp[w] || dp[w - num];
return dp[target];

