String DP (LCS / Edit Distance).code:
// --- Longest Common Subsequence ---
// dp[i][j] = LCS of s1[0..i-1] and s2[0..j-1]
int m = s1.size(), n = s2.size();
vector<vector<int>> dp(m + 1, vector<int>(n + 1, 0));
for (int i = 1; i <= m; i++) {
    for (int j = 1; j <= n; j++) {
        if (s1[i-1] == s2[j-1]) dp[i][j] = dp[i-1][j-1] + 1;
        else                     dp[i][j] = max(dp[i-1][j], dp[i][j-1]);
    }
}
return dp[m][n];

// --- Edit Distance (Levenshtein) ---
// dp[i][j] = min operations to transform word1[0..i-1] into word2[0..j-1]
vector<vector<int>> dp(m + 1, vector<int>(n + 1));
for (int i = 0; i <= m; i++) dp[i][0] = i; // Delete all of word1
for (int j = 0; j <= n; j++) dp[0][j] = j; // Insert all of word2
for (int i = 1; i <= m; i++) {
    for (int j = 1; j <= n; j++) {
        if (word1[i-1] == word2[j-1])
            dp[i][j] = dp[i-1][j-1]; // No operation needed
        else
            dp[i][j] = 1 + min({dp[i-1][j],    // Delete from word1
                                 dp[i][j-1],    // Insert into word1
                                 dp[i-1][j-1]   // Replace
                                });
    }
}
return dp[m][n];

