        int r = l + len - 1;
        for (int k = l; k <= r; k++) {      // k = LAST operation in [l, r]
            int lv = (k > l) ? dp[l][k-1] : 0;
            int rv = (k < r) ? dp[k+1][r] : 0;
            dp[l][r] = max(dp[l][r], lv + score(k) + rv);
        }
    }
}
return dp[0][n-1];

