// Dimensions: [position][is_tight/limit][has_leading_zero][custom_state]

long long dfs(int pos, bool limit, bool lead, int state, const string& num) {
    if (pos == (int)num.size()) {
        // Base case: reached end of number
        return isValid(state) ? 1 : 0;
    }
    if (memo[pos][limit][lead][state] != -1)
        return memo[pos][limit][lead][state];

    int up = limit ? (num[pos] - '0') : 9; // Max digit we can place
    long long res = 0;

    for (int d = 0; d <= up; d++) {
        bool next_limit = limit && (d == up);   // Still tight if we chose max digit
        bool next_lead  = lead  && (d == 0);    // Still leading zero
        int  next_state = transition(state, d, next_lead);

        res += dfs(pos + 1, next_limit, next_lead, next_state, num);
    }
    return memo[pos][limit][lead][state] = res;
}

