const long long MOD = 1e9 + 7;

// Fast exponentiation: computes (base^exp) % MOD
long long power(long long base, long long exp) {
    long long res = 1;
    base %= MOD;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % MOD;
        base = (base * base) % MOD;
        exp /= 2;
    }
    return res;
}

// Modular inverse via Fermat's Little Theorem: a^-1 = a^(p-2) mod p
// Valid only when MOD is a prime and a is not divisible by MOD
long long modInverse(long long n) { return power(n, MOD - 2); }

// Precompute factorials, then nCr in O(1)
