for (int i = 1; i < MAXN; i++) fact[i] = fact[i-1] * i % MOD;

long long nCr(int n, int r) {
    if (r < 0 || r > n) return 0;
    return fact[n] % MOD * modInverse(fact[r]) % MOD * modInverse(fact[n-r]) % MOD;
}

