auto getHash = [&](int L, int R) -> long long {
    long long h1 = hash_val[R + 1];
    long long h2 = pw[R - L + 1] * hash_val[L] % MOD;
    return (h1 - h2 + MOD) % MOD; // +MOD prevents negative result
};

