struct BIT {
    int n;
    vector<int> tree;
    BIT(int n) : n(n), tree(n + 1, 0) {} // 1-indexed

    // Add delta to position i (1-indexed)
    void update(int i, int delta) {
        for (; i <= n; i += i & (-i)) // Move to next responsible node
            tree[i] += delta;
    }

    // Prefix sum [1, i] (1-indexed)
    int query(int i) {
        int sum = 0;
        for (; i > 0; i -= i & (-i)) // Move to parent node
            sum += tree[i];
        return sum;
    }

    // Range sum [l, r] (1-indexed)
    int query(int l, int r) {
        return query(r) - query(l - 1);
    }
};

LRU Cache.code:
class LRUCache {
    int cap;
    // Doubly linked list: front = most recently used, back = least recently used
    list<pair<int,int>> cache; // {key, value}
    unordered_map<int, list<pair<int,int>>::iterator> mp; // key -> iterator
public:
    LRUCache(int capacity) : cap(capacity) {}

    int get(int key) {
        if (!mp.count(key)) return -1;
        // Move accessed node to front (mark as most recently used)
        cache.splice(cache.begin(), cache, mp[key]);
        return mp[key]->second;
    }

    void put(int key, int value) {
        if (mp.count(key)) {
            mp[key]->second = value;
            cache.splice(cache.begin(), cache, mp[key]); // Move to front
        } else {
            if ((int)cache.size() == cap) { // Evict LRU (back of list)
                mp.erase(cache.back().first);
                cache.pop_back();
            }
            cache.push_front({key, value});
            mp[key] = cache.begin();
        }
    }
};
